CREATE TABLE IF NOT EXISTS public.pl_budget_lines (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  period text NOT NULL,
  budget_year integer NOT NULL,
  section text NOT NULL,
  line_key text NOT NULL,
  line_label text NOT NULL,
  kind text NOT NULL DEFAULT 'cost',
  amount numeric(14,2) NOT NULL DEFAULT 0,
  source_workbook text NOT NULL,
  source_sheet text NOT NULL,
  source_label text NOT NULL,
  sort_order integer NOT NULL DEFAULT 0,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now(),
  CONSTRAINT pl_budget_lines_period_check CHECK (period ~ '^\d{4}-\d{2}$'),
  CONSTRAINT pl_budget_lines_section_check CHECK (
    section IN (
      'revenue',
      'cost_of_goods',
      'personnel',
      'housing',
      'sales_marketing',
      'general_admin',
      'depreciation',
      'financial',
      'tax',
      'other'
    )
  ),
  CONSTRAINT pl_budget_lines_kind_check CHECK (kind IN ('revenue', 'cost'))
);

CREATE UNIQUE INDEX IF NOT EXISTS pl_budget_lines_source_unique
  ON public.pl_budget_lines (source_workbook, period, line_key);

CREATE INDEX IF NOT EXISTS idx_pl_budget_lines_period
  ON public.pl_budget_lines (period, section, sort_order);

GRANT SELECT, INSERT, UPDATE, DELETE ON public.pl_budget_lines TO authenticated;
GRANT ALL ON public.pl_budget_lines TO service_role;

ALTER TABLE public.pl_budget_lines ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "pl_budget_lines_select_auth" ON public.pl_budget_lines;
CREATE POLICY "pl_budget_lines_select_auth"
  ON public.pl_budget_lines FOR SELECT TO authenticated USING (true);

DROP POLICY IF EXISTS "pl_budget_lines_write_auth" ON public.pl_budget_lines;
CREATE POLICY "pl_budget_lines_write_auth"
  ON public.pl_budget_lines FOR ALL TO authenticated
  USING (auth.uid() IS NOT NULL)
  WITH CHECK (auth.uid() IS NOT NULL);

DROP TRIGGER IF EXISTS trg_pl_budget_lines_updated_at ON public.pl_budget_lines;
CREATE TRIGGER trg_pl_budget_lines_updated_at
  BEFORE UPDATE ON public.pl_budget_lines
  FOR EACH ROW EXECUTE FUNCTION public.tg_set_updated_at();

